Date: Tue, 4 Mar 2025 14:26:05 +0100
Subject: [PATCH] f_decoder_wrapper: don't wait on self thread progress on
 reinit

Fixes deadlock when reinit is triggered by the thread itself.

Fixes: #15776
---
 filters/f_decoder_wrapper.c | 8 +++++++-
 1 file changed, 7 insertions(+), 1 deletion(-)

diff --git a/filters/f_decoder_wrapper.c b/filters/f_decoder_wrapper.c
index aa5170f915e66..60d2014b938d3 100644
--- a/filters/f_decoder_wrapper.c
+++ b/filters/f_decoder_wrapper.c
@@ -474,6 +474,12 @@ static bool reinit_decoder(struct priv *p)
     return !!p->decoder;
 }

+static bool decoder_wrapper_reinit(struct mp_decoder_wrapper *d)
+{
+    struct priv *p = d->f->priv;
+    return reinit_decoder(p);
+}
+
 bool mp_decoder_wrapper_reinit(struct mp_decoder_wrapper *d)
 {
     struct priv *p = d->f->priv;
@@ -1056,7 +1062,7 @@ static void read_frame(struct priv *p)
         if (new_segment->segmented) {
             if (p->codec != new_segment->codec) {
                 p->codec = new_segment->codec;
-                if (!mp_decoder_wrapper_reinit(&p->public))
+                if (!decoder_wrapper_reinit(&p->public))
                     mp_filter_internal_mark_failed(p->decf);
             }

From 2b0116f0ebf32120d8378df5e5ea19a15df6c618 Mon Sep 17 00:00:00 2001
From: Robin Appelman <robin@icewind.nl>
Date: Tue, 1 Apr 2025 17:29:58 +0200
Subject: [PATCH] fix: don't have sabre/dav send it's own reponse if we already
 send the zip response

Signed-off-by: Robin Appelman <robin@icewind.nl>
---
 .../dav/lib/Connector/Sabre/ZipFolderPlugin.php | 17 +++++++++++++++++
 1 file changed, 17 insertions(+)

diff --git a/apps/dav/lib/Connector/Sabre/ZipFolderPlugin.php b/apps/dav/lib/Connector/Sabre/ZipFolderPlugin.php
index 7e92dd18c83bd..220988caba0ae 100644
--- a/apps/dav/lib/Connector/Sabre/ZipFolderPlugin.php
+++ b/apps/dav/lib/Connector/Sabre/ZipFolderPlugin.php
@@ -55,6 +55,8 @@ public function __construct(
 	public function initialize(Server $server): void {
 		$this->server = $server;
 		$this->server->on('method:GET', $this->handleDownload(...), 100);
+		// low priority to give any other afterMethod:* a chance to fire before we cancel everything
+		$this->server->on('afterMethod:GET', $this->afterDownload(...), 999);
 	}

 	/**
@@ -172,4 +174,19 @@ public function handleDownload(Request $request, Response $response): ?bool {
 		$streamer->finalize();
 		return false;
 	}
+
+	/**
+	 * Tell sabre/dav not to trigger it's own response sending logic as the handleDownload will have already send the response
+	 *
+	 * @return false|null
+	 */
+	public function afterDownload(Request $request, Response $response): ?bool {
+		$node = $this->tree->getNodeForPath($request->getPath());
+		if (!($node instanceof Directory)) {
+			// only handle directories
+			return null;
+		} else {
+			return false;
+		}
+	}
 }

